from collections import deque

class Solution:
    def canReachCorner(self, xCorner, yCorner, circles):
        m = len(circles)

        def touches_left(cx, cy, r):
            cyc = min(max(cy, 0), yCorner)
            return cx * cx + (cy - cyc) ** 2 <= r * r

        def touches_right(cx, cy, r):
            cyc = min(max(cy, 0), yCorner)
            return (cx - xCorner) ** 2 + (cy - cyc) ** 2 <= r * r

        def touches_top(cx, cy, r):
            cxc = min(max(cx, 0), xCorner)
            return (cx - cxc) ** 2 + (cy - yCorner) ** 2 <= r * r

        def touches_bottom(cx, cy, r):
            cxc = min(max(cx, 0), xCorner)
            return (cx - cxc) ** 2 + cy * cy <= r * r

        TOP_LEFT, BOTTOM_RIGHT = m, m + 1
        adj = [[] for _ in range(m + 2)]
        for i, (cx, cy, r) in enumerate(circles):
            if touches_left(cx, cy, r) or touches_top(cx, cy, r):
                adj[i].append(TOP_LEFT)
                adj[TOP_LEFT].append(i)
            if touches_right(cx, cy, r) or touches_bottom(cx, cy, r):
                adj[i].append(BOTTOM_RIGHT)
                adj[BOTTOM_RIGHT].append(i)
        for i in range(m):
            cxi, cyi, ri = circles[i]
            for j in range(i + 1, m):
                cxj, cyj, rj = circles[j]
                if (cxi - cxj) ** 2 + (cyi - cyj) ** 2 <= (ri + rj) ** 2:
                    adj[i].append(j)
                    adj[j].append(i)
        visited = [False] * (m + 2)
        visited[TOP_LEFT] = True
        q = deque([TOP_LEFT])
        while q:
            u = q.popleft()
            for v in adj[u]:
                if not visited[v]:
                    visited[v] = True
                    q.append(v)
        return not visited[BOTTOM_RIGHT]

