                parent[a] = parent[parent[a]]
                a = parent[a]
            return a

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        def touches_left(cx, cy, r):
            cyc = min(max(cy, 0), yCorner)
            return cx * cx + (cy - cyc) ** 2 <= r * r

        def touches_right(cx, cy, r):
            cyc = min(max(cy, 0), yCorner)
            return (cx - xCorner) ** 2 + (cy - cyc) ** 2 <= r * r

        def touches_top(cx, cy, r):
            cxc = min(max(cx, 0), xCorner)
            return (cx - cxc) ** 2 + (cy - yCorner) ** 2 <= r * r

        def touches_bottom(cx, cy, r):
            cxc = min(max(cx, 0), xCorner)
            return (cx - cxc) ** 2 + cy * cy <= r * r

        for i, (cx, cy, r) in enumerate(circles):
            if touches_left(cx, cy, r) or touches_top(cx, cy, r):
                union(i, TOP_LEFT)
            if touches_right(cx, cy, r) or touches_bottom(cx, cy, r):
                union(i, BOTTOM_RIGHT)
        for i in range(m):
            cxi, cyi, ri = circles[i]
            for j in range(i + 1, m):
