var canReachCorner = function(xCorner, yCorner, circles) {
    const m = circles.length;
    const parent = new Array(m + 2);
    for (let i = 0; i < m + 2; i++) parent[i] = i;
    const TOP_LEFT = m, BOTTOM_RIGHT = m + 1;
    function find(a) {
        while (parent[a] !== a) {
            parent[a] = parent[parent[a]];
            a = parent[a];
        }
        return a;
    }
    function union(a, b) {
        const ra = find(a), rb = find(b);
        if (ra !== rb) parent[ra] = rb;
    }
    const X = BigInt(xCorner), Y = BigInt(yCorner);
    function clampBig(v, lo, hi) {
        if (v < lo) return lo;
        if (v > hi) return hi;
        return v;
    }
    function touchesLeft(cx, cy, r) {
        const cyc = clampBig(cy, 0n, Y);
        const dy = cy - cyc;
        return cx * cx + dy * dy <= r * r;
    }
    function touchesRight(cx, cy, r) {
        const cyc = clampBig(cy, 0n, Y);
        const dx = cx - X;
        const dy = cy - cyc;
        return dx * dx + dy * dy <= r * r;
    }
    function touchesTop(cx, cy, r) {
        const cxc = clampBig(cx, 0n, X);
        const dx = cx - cxc;
        const dy = cy - Y;
        return dx * dx + dy * dy <= r * r;
    }
    function touchesBottom(cx, cy, r) {
        const cxc = clampBig(cx, 0n, X);
        const dx = cx - cxc;
        return dx * dx + cy * cy <= r * r;
    }
    const cxs = new Array(m), cys = new Array(m), rs = new Array(m);
    for (let i = 0; i < m; i++) {
        const c = circles[i];
        const cx = BigInt(c[0]), cy = BigInt(c[1]), r = BigInt(c[2]);
        cxs[i] = cx; cys[i] = cy; rs[i] = r;
        if (touchesLeft(cx, cy, r) || touchesTop(cx, cy, r)) union(i, TOP_LEFT);
        if (touchesRight(cx, cy, r) || touchesBottom(cx, cy, r)) union(i, BOTTOM_RIGHT);
    }
    for (let i = 0; i < m; i++) {
        for (let j = i + 1; j < m; j++) {
            const ddx = cxs[i] - cxs[j];
            const ddy = cys[i] - cys[j];
            const rr = rs[i] + rs[j];
            if (ddx * ddx + ddy * ddy <= rr * rr) union(i, j);
        }
    }
    return find(TOP_LEFT) !== find(BOTTOM_RIGHT);
};
